// ─── AllStyles (computed at module load from TailwindStyles + custom colors) ──

const _allSet = new Set<string>();
for (const key of Object.keys(TailwindStyles)) {
  const arr = TailwindStyles[key];
  if (Array.isArray(arr)) for (const cls of arr) if (cls) _allSet.add(cls);
}
// Custom PageHub color variants
for (const color of ["primary", "secondary", "accent"]) {
  for (const shade of ["50","100","200","300","400","500","600","700","800","900","950","DEFAULT"]) {
    const suffix = shade === "DEFAULT" ? "" : `-${shade}`;
    _allSet.add(`bg-${color}${suffix}`);
    _allSet.add(`text-${color}${suffix}`);
    _allSet.add(`border-${color}${suffix}`);
  }
}
export const AllStylesSet = _allSet;
export const AllStyles: string[] = [..._allSet];

